     1|/**
     2| * IVX Owner — Security Box (GitHub + Render)
     3| *
     4| * Live security posture panel for the two production deployment platforms.
     5| * Pulls real, verified status from the backend deployment-tools routes:
     6| *   - GET /api/ivx/deploy-tools/github      — token, perms, branches, commit
     7| *   - GET /api/ivx/deploy-tools/render      — service, deploys, env vars
     8| *   - GET /api/ivx/deploy-tools/credentials — masked credential sync
     9| *   - GET /api/ivx/deploy-tools/dashboard   — unified summary
    10| *
    11| * No secrets are ever displayed. Values are masked server-side. Blockers are
    12| * reported honestly with the exact missing/expired credential name.
    13| */
    14|import { useCallback, useMemo, useState } from 'react';
    15|import { useQuery } from '@tanstack/react-query';
    16|import { Stack } from 'expo-router';
    17|import {
    18|  ActivityIndicator,
    19|  Pressable,
    20|  RefreshControl,
    21|  ScrollView,
    22|  StyleSheet,
    23|  Text,
    24|  View,
    25|} from 'react-native';
    26|import {
    27|  AlertTriangle,
    28|  CheckCircle2,
    29|  Eye,
    30|  EyeOff,
    31|  Github,
    32|  KeyRound,
    33|  Lock,
    34|  Rocket,
    35|  ShieldAlert,
    36|  ShieldCheck,
    37|  XCircle,
    38|} from 'lucide-react-native';
    39|import * as Clipboard from 'expo-clipboard';
    40|import * as Haptics from 'expo-haptics';
    41|import { useSafeAreaInsets } from 'react-native-safe-area-context';
    42|import ErrorBoundary from '@/components/ErrorBoundary';
    43|import Colors from '@/constants/colors';
    44|
    45|const API_BASE = ((process.env.EXPO_PUBLIC_IVX_API_BASE_URL
    46|  ?? process.env.EXPO_PUBLIC_API_BASE_URL
    47|  ?? 'https://api.ivxholding.com') as string).replace(/\/$/, '');
    48|
    49|// ─── Backend response shapes (only the fields we render) ────────────────
    50|
    51|type GitHubPermissions = {
    52|  scopes?: string[];
    53|  repoAccess?: boolean;
    54|  workflowAccess?: boolean;
    55|  adminAccess?: boolean;
    56|  canPush?: boolean;
    57|  canReadWorkflows?: boolean;
    58|  canReadSecrets?: boolean;
    59|} | null;
    60|
    61|type GitHubCommit = {
    62|  sha: string;
    63|  shortSha: string;
    64|  message: string;
    65|  author: string | null;
    66|  date: string | null;
    67|  url: string;
    68|} | null;
    69|
    70|type GitHubBranch = { name: string; sha: string; protected: boolean };
    71|
    72|type GitHubStatusResponse = {
    73|  ok: boolean;
    74|  error?: string | null;
    75|  branches?: GitHubBranch[];
    76|  commit?: GitHubCommit;
    77|  permissions?: GitHubPermissions;
    78|};
    79|
    80|type RenderService = {
    81|  id: string;
    82|  name: string;
    83|  type: string;
    84|  repo: string;
    85|  branch: string;
    86|  autoDeploy: string;
    87|  suspended: string;
    88|} | null;
    89|
    90|type RenderDeploy = {
    91|  id: string;
    92|  status: string;
    93|  commitSha: string | null;
    94|  commitMessage: string | null;
    95|  createdAt: string | null;
    96|  finishedAt: string | null;
    97|  failureReason: string | null;
    98|};
    99|
   100|type RenderStatusResponse = {
   101|  ok: boolean;
   102|  error?: string | null;
   103|  service?: RenderService;
   104|  deploys?: RenderDeploy[];
   105|  envVarsCount?: number;
   106|  autoDeploy?: boolean | null;
   107|};
   108|
   109|type CredentialSource = 'process.env' | 'owner_variables' | 'github_secrets' | 'render_env' | 'vercel_env' | 'supabase_vault' | 'unknown';
   110|type CredentialValidation = 'valid' | 'missing' | 'expired' | 'wrong_scope' | 'auth_failed' | 'network_error' | 'unverified';
   111|
   112|type CredentialRow = {
   113|  name: string;
   114|  category: 'github' | 'render' | 'supabase' | 'vercel' | 'aws' | 'ai' | 'security' | 'other';
   115|  required: boolean;
   116|  validation: CredentialValidation;
   117|  validationDetail: string | null;
   118|  sources: { source: CredentialSource; present: boolean }[];
   119|  tested: boolean;
   120|};
   121|
   122|type CredentialsResponse = {
   123|  ok: boolean;
   124|  credentials?: CredentialRow[];
   125|  summary?: { total: number; valid: number; missing: number; failed: number; unverified: number };
   126|  gaps?: string[];
   127|  recommendations?: string[];
   128|};
   129|
   130|// ─── Helpers ────────────────────────────────────────────────────────────
   131|
   132|async function fetchJson<T>(path: string): Promise<T> {
   133|  const res = await fetch(`${API_BASE}${path}`, {
   134|    headers: { Accept: 'application/json' },
   135|  });
   136|  if (!res.ok) {
   137|    const text = await res.text().catch(() => '');
   138|    throw new Error(`HTTP ${res.status} ${res.statusText}${text ? ` — ${text.slice(0, 200)}` : ''}`);
   139|  }
   140|  return (await res.json()) as T;
   141|}
   142|
   143|function platformState(
   144|  ok: boolean,
   145|  error?: string | null,
   146|): 'READY' | 'BLOCKED' | 'DEGRADED' {
   147|  if (ok && !error) return 'READY';
   148|  if (error && /not configured|missing|401|403|invalid|expired/i.test(error)) return 'BLOCKED';
   149|  return 'DEGRADED';
   150|}
   151|
   152|function stateColor(state: 'READY' | 'BLOCKED' | 'DEGRADED'): string {
   153|  if (state === 'READY') return Colors.success;
   154|  if (state === 'BLOCKED') return Colors.error;
   155|  return Colors.warning;
   156|}
   157|
   158|function stateIcon(state: 'READY' | 'BLOCKED' | 'DEGRADED', size = 18) {
   159|  if (state === 'READY') return <CheckCircle2 size={size} color={Colors.success} />;
   160|  if (state === 'BLOCKED') return <XCircle size={size} color={Colors.error} />;
   161|  return <AlertTriangle size={size} color={Colors.warning} />;
   162|}
   163|
   164|function credColor(v: CredentialValidation): string {
   165|  if (v === 'valid') return Colors.success;
   166|  if (v === 'missing') return Colors.error;
   167|  if (v === 'auth_failed' || v === 'expired' || v === 'wrong_scope') return Colors.error;
   168|  if (v === 'network_error') return Colors.warning;
   169|  return Colors.textTertiary;
   170|}
   171|
   172|function credLabel(v: CredentialValidation): string {
   173|  return v.toUpperCase().replace(/_/g, ' ');
   174|}
   175|
   176|function maskCommitSha(sha: string | null): string {
   177|  if (!sha) return '—';
   178|  return sha.length > 12 ? `${sha.slice(0, 8)}…${sha.slice(-4)}` : sha;
   179|}
   180|
   181|function formatTimestamp(value: string | null): string {
   182|  if (!value) return '—';
   183|  const d = new Date(value);
   184|  if (Number.isNaN(d.getTime())) return '—';
   185|  return d.toLocaleString([], { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' });
   186|}
   187|
   188|// ─── Components ─────────────────────────────────────────────────────────
   189|
   190|function StateBanner({ state, label, error }: { state: 'READY' | 'BLOCKED' | 'DEGRADED'; label: string; error?: string | null }) {
   191|  const color = stateColor(state);
   192|  return (
   193|    <View style={[styles.stateBanner, { borderColor: color + '44', backgroundColor: color + '12' }]}>
   194|      {stateIcon(state, 22)}
   195|      <View style={styles.stateBannerText}>
   196|        <Text style={[styles.stateBannerLabel, { color }]}>{label}</Text>
   197|        <Text style={styles.stateBannerSub}>
   198|          {state === 'READY'
   199|            ? 'Token valid · permissions verified live'
   200|            : state === 'BLOCKED'
   201|              ? (error || 'BLOCKED — exact blocker below')
   202|              : (error || 'Degraded — partial reachability')}
   203|        </Text>
   204|      </View>
   205|      <View style={[styles.statePill, { backgroundColor: color }]}>
   206|        <Text style={styles.statePillText}>{state}</Text>
   207|      </View>
   208|    </View>
   209|  );
   210|}
   211|
   212|function PermRow({ label, value }: { label: string; value: boolean | null | undefined }) {
   213|  const ok = value === true;
   214|  const unknown = value === null || value === undefined;
   215|  const color = unknown ? Colors.textTertiary : ok ? Colors.success : Colors.error;
   216|  return (
   217|    <View style={styles.permRow}>
   218|      {unknown ? <EyeOff size={14} color={Colors.textTertiary} /> : ok ? <CheckCircle2 size={14} color={Colors.success} /> : <XCircle size={14} color={Colors.error} />}
   219|      <Text style={styles.permLabel}>{label}</Text>
   220|      <Text style={[styles.permValue, { color }]}>{unknown ? 'UNKNOWN' : ok ? 'YES' : 'NO'}</Text>
   221|    </View>
   222|  );
   223|}
   224|
   225|function CredentialCard({ row }: { row: CredentialRow }) {
   226|  const color = credColor(row.validation);
   227|  const sources = row.sources.filter((s) => s.present);
   228|  return (
   229|    <View style={[styles.credCard, { borderColor: color + '55' }]}>
   230|      <View style={styles.credHeader}>
   231|        {row.validation === 'valid' ? <CheckCircle2 size={15} color={Colors.success} /> : row.validation === 'missing' ? <XCircle size={15} color={Colors.error} /> : <AlertTriangle size={15} color={Colors.warning} />}
   232|        <Text style={styles.credName} numberOfLines={1}>{row.name}</Text>
   233|        {row.required ? <View style={styles.requiredPill}><Text style={styles.requiredPillText}>REQUIRED</Text></View> : null}
   234|        <View style={[styles.credPill, { backgroundColor: color }]}>
   235|          <Text style={styles.credPillText}>{credLabel(row.validation)}</Text>
   236|        </View>
   237|      </View>
   238|      {row.validationDetail ? <Text style={styles.credDetail}>{row.validationDetail}</Text> : null}
   239|      <View style={styles.credMetaRow}>
   240|        <Text style={styles.credMetaLabel}>Sources:</Text>
   241|        <Text style={styles.credMetaValue}>
   242|          {sources.length > 0 ? sources.map((s) => s.source).join(' · ') : 'none found'}
   243|        </Text>
   244|      </View>
   245|      <View style={styles.credMetaRow}>
   246|        <Text style={styles.credMetaLabel}>Tested:</Text>
   247|        <Text style={styles.credMetaValue}>{row.tested ? 'yes (live probe)' : 'presence only'}</Text>
   248|      </View>
   249|    </View>
   250|  );
   251|}
   252|
   253|function SectionHeader({ icon, title, subtitle }: { icon: React.ReactNode; title: string; subtitle?: string }) {
   254|  return (
   255|    <View style={styles.sectionHeader}>
   256|      {icon}
   257|      <View style={styles.sectionHeaderText}>
   258|        <Text style={styles.sectionTitle}>{title}</Text>
   259|        {subtitle ? <Text style={styles.sectionSubtitle}>{subtitle}</Text> : null}
   260|      </View>
   261|    </View>
   262|  );
   263|}
   264|
   265|function BlockerList({ items }: { items: string[] }) {
   266|  if (items.length === 0) return null;
   267|  return (
   268|    <View style={styles.blockerBox}>
   269|      <ShieldAlert size={16} color={Colors.error} />
   270|      <View style={styles.blockerTextWrap}>
   271|        {items.map((b, i) => (
   272|          <Text key={`${b}-${i}`} style={styles.blockerText}>• {b}</Text>
   273|        ))}
   274|      </View>
   275|    </View>
   276|  );
   277|}
   278|
   279|// ─── Screen ─────────────────────────────────────────────────────────────
   280|
   281|export default function IVXSecurityBoxScreen() {
   282|  const insets = useSafeAreaInsets();
   283|  const [revealSecrets, setRevealSecrets] = useState<boolean>(false);
   284|
   285|  const githubQ = useQuery<GitHubStatusResponse>({
   286|    queryKey: ['ivx-security-box', 'github'],
   287|    queryFn: () => fetchJson<GitHubStatusResponse>('/api/ivx/deploy-tools/github'),
   288|    retry: 1,
   289|    staleTime: 30_000,
   290|  });
   291|
   292|  const renderQ = useQuery<RenderStatusResponse>({
   293|    queryKey: ['ivx-security-box', 'render'],
   294|    queryFn: () => fetchJson<RenderStatusResponse>('/api/ivx/deploy-tools/render'),
   295|    retry: 1,
   296|    staleTime: 30_000,
   297|  });
   298|
   299|  const credsQ = useQuery<CredentialsResponse>({
   300|    queryKey: ['ivx-security-box', 'credentials'],
   301|    queryFn: () => fetchJson<CredentialsResponse>('/api/ivx/deploy-tools/credentials'),
   302|    retry: 1,
   303|    staleTime: 30_000,
   304|  });
   305|
   306|  const refreshAll = useCallback(async () => {
   307|    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
   308|    await Promise.all([githubQ.refetch(), renderQ.refetch(), credsQ.refetch()]);
   309|  }, [credsQ, githubQ, renderQ]);
   310|
   311|  const refreshControl = (
   312|    <RefreshControl
   313|      refreshing={githubQ.isFetching || renderQ.isFetching || credsQ.isFetching}
   314|      onRefresh={refreshAll}
   315|      tintColor={Colors.tint}
   316|      colors={[Colors.tint]}
   317|    />
   318|  );
   319|
   320|  const ghState = platformState(githubQ.data?.ok ?? false, githubQ.data?.error ?? githubQ.error?.message);
   321|  const renderState = platformState(renderQ.data?.ok ?? false, renderQ.data?.error ?? renderQ.error?.message);
   322|
   323|  const ghCreds = useMemo(
   324|    () => (credsQ.data?.credentials ?? []).filter((c) => c.category === 'github'),
   325|    [credsQ.data],
   326|  );
   327|  const renderCreds = useMemo(
   328|    () => (credsQ.data?.credentials ?? []).filter((c) => c.category === 'render'),
   329|    [credsQ.data],
   330|  );
   331|  const otherCreds = useMemo(
   332|    () => (credsQ.data?.credentials ?? []).filter((c) => c.category !== 'github' && c.category !== 'render'),
   333|    [credsQ.data],
   334|  );
   335|
   336|  const ghBlockers = useMemo(() => {
   337|    const blockers: string[] = [];
   338|    if (githubQ.data?.error) blockers.push(`GitHub API: ${githubQ.data.error}`);
   339|    if (githubQ.error && !githubQ.data) blockers.push(`Network: ${githubQ.error.message}`);
   340|    ghCreds.filter((c) => c.required && c.validation === 'missing').forEach((c) => blockers.push(`${c.name} — REQUIRED credential missing`));
   341|    ghCreds.filter((c) => c.validation === 'auth_failed' || c.validation === 'expired').forEach((c) => blockers.push(`${c.name} — ${c.validationDetail ?? credLabel(c.validation)}`));
   342|    return blockers;
   343|  }, [ghCreds, githubQ.data?.error, githubQ.error]);
   344|
   345|  const renderBlockers = useMemo(() => {
   346|    const blockers: string[] = [];
   347|    if (renderQ.data?.error) blockers.push(`Render API: ${renderQ.data.error}`);
   348|    if (renderQ.error && !renderQ.data) blockers.push(`Network: ${renderQ.error.message}`);
   349|    renderCreds.filter((c) => c.required && c.validation === 'missing').forEach((c) => blockers.push(`${c.name} — REQUIRED credential missing`));
   350|    renderCreds.filter((c) => c.validation === 'auth_failed' || c.validation === 'expired').forEach((c) => blockers.push(`${c.name} — ${c.validationDetail ?? credLabel(c.validation)}`));
   351|    if (renderQ.data?.service?.suspended && renderQ.data.service.suspended !== 'not_suspended') {
   352|      blockers.push(`Render service suspended: ${renderQ.data.service.suspended}`);
   353|    }
   354|    return blockers;
   355|  }, [renderCreds, renderQ.data?.error, renderQ.data?.service, renderQ.error]);
   356|
   357|  const latestDeploy = renderQ.data?.deploys?.[0] ?? null;
   358|  const perms = githubQ.data?.permissions ?? null;
   359|  const summary = credsQ.data?.summary;
   360|  const gaps = credsQ.data?.gaps ?? [];
   361|
   362|  const copyBlockers = useCallback(async (blockers: string[], label: string) => {
   363|    const text = `${label} blockers:\n${blockers.length ? blockers.map((b) => `- ${b}`).join('\n') : 'none'}`;
   364|    await Clipboard.setStringAsync(text);
   365|    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
   366|  }, []);
   367|
   368|  return (
   369|    <ErrorBoundary>
   370|      <Stack.Screen options={{ title: 'Security Box · GitHub + Render', headerShown: true }} />
   371|      <ScrollView
   372|        style={styles.root}
   373|        contentContainerStyle={[styles.scrollContent, { paddingBottom: 40 + insets.bottom }]}
   374|        refreshControl={refreshControl}
   375|        testID="ivx-security-box-screen"
   376|      >
   377|        {/* Top summary */}
   378|        <View style={styles.summaryCard}>
   379|          <View style={styles.summaryHeader}>
   380|            <ShieldCheck size={22} color={Colors.tint} />
   381|            <Text style={styles.summaryTitle}>Platform Security Box</Text>
   382|          </View>
   383|          <Text style={styles.summarySub}>
   384|            Live, verified posture for the two production deployment platforms. Tokens are probed server-side; values are masked and never exposed.
   385|          </Text>
   386|          <View style={styles.summaryGrid}>
   387|            <View style={styles.summaryCell}>
   388|              <Text style={styles.summaryCellLabel}>GitHub</Text>
   389|              <Text style={[styles.summaryCellValue, { color: stateColor(ghState) }]}>{ghState}</Text>
   390|            </View>
   391|            <View style={styles.summaryCell}>
   392|              <Text style={styles.summaryCellLabel}>Render</Text>
   393|              <Text style={[styles.summaryCellValue, { color: stateColor(renderState) }]}>{renderState}</Text>
   394|            </View>
   395|            <View style={styles.summaryCell}>
   396|              <Text style={styles.summaryCellLabel}>Creds valid</Text>
   397|              <Text style={styles.summaryCellValue}>{summary?.valid ?? '—'}<Text style={styles.summaryCellSub}>/{summary?.total ?? '—'}</Text></Text>
   398|            </View>
   399|            <View style={styles.summaryCell}>
   400|              <Text style={styles.summaryCellLabel}>Missing</Text>
   401|              <Text style={[styles.summaryCellValue, { color: (summary?.missing ?? 0) > 0 ? Colors.error : Colors.text }]}>{summary?.missing ?? '—'}</Text>
   402|            </View>
   403|          </View>
   404|        </View>
   405|
   406|        {/* GitHub panel */}
   407|        <SectionHeader
   408|          icon={<Github size={20} color={Colors.tint} />}
   409|          title="GitHub Security Box"
   410|          subtitle="Token · permissions · repo · latest commit"
   411|        />
   412|        <View style={styles.panel}>
   413|          <StateBanner state={ghState} label="GitHub" error={githubQ.data?.error ?? githubQ.error?.message} />
   414|          {githubQ.isLoading ? <ActivityIndicator color={Colors.tint} style={styles.loader} /> : null}
   415|
   416|          <View style={styles.block}>
   417|            <Text style={styles.blockTitle}>Token permissions (live)</Text>
   418|            <PermRow label="Repo access" value={perms?.repoAccess} />
   419|            <PermRow label="Can push" value={perms?.canPush} />
   420|            <PermRow label="Read workflows" value={perms?.canReadWorkflows} />
   421|            <PermRow label="Read secrets" value={perms?.canReadSecrets} />
   422|            <PermRow label="Workflow access" value={perms?.workflowAccess} />
   423|            <PermRow label="Admin" value={perms?.adminAccess} />
   424|          </View>
   425|
   426|          <View style={styles.block}>
   427|            <Text style={styles.blockTitle}>Repository</Text>
   428|            <View style={styles.kvRow}>
   429|              <Text style={styles.kvLabel}>Default branch</Text>
   430|              <Text style={styles.kvValue}>
   431|                {(githubQ.data?.branches ?? []).find((b) => b.name === 'main') ? 'main' : (githubQ.data?.branches?.[0]?.name ?? '—')}
   432|              </Text>
   433|            </View>
   434|            <View style={styles.kvRow}>
   435|              <Text style={styles.kvLabel}>Branches</Text>
   436|              <Text style={styles.kvValue}>{githubQ.data?.branches?.length ?? 0}</Text>
   437|            </View>
   438|            <View style={styles.kvRow}>
   439|              <Text style={styles.kvLabel}>Protected branches</Text>
   440|              <Text style={styles.kvValue}>{(githubQ.data?.branches ?? []).filter((b) => b.protected).length}</Text>
   441|            </View>
   442|            <View style={styles.kvRow}>
   443|              <Text style={styles.kvLabel}>Latest commit</Text>
   444|              <Text style={styles.kvValue}>{maskCommitSha(githubQ.data?.commit?.sha ?? null)}</Text>
   445|            </View>
   446|            {githubQ.data?.commit?.message ? (
   447|              <View style={styles.kvRow}>
   448|                <Text style={styles.kvLabel}>Message</Text>
   449|                <Text style={styles.kvValueFlex} numberOfLines={2}>{githubQ.data.commit.message}</Text>
   450|              </View>
   451|            ) : null}
   452|            <View style={styles.kvRow}>
   453|              <Text style={styles.kvLabel}>Pushed at</Text>
   454|              <Text style={styles.kvValue}>{formatTimestamp(githubQ.data?.commit?.date ?? null)}</Text>
   455|            </View>
   456|          </View>
   457|
   458|          <Text style={styles.subBlockTitle}>GitHub credentials ({ghCreds.length})</Text>
   459|          {ghCreds.map((c) => <CredentialCard key={c.name} row={c} />)}
   460|          {ghCreds.length === 0 && !credsQ.isLoading ? (
   461|            <Text style={styles.emptyText}>No GitHub credentials registered.</Text>
   462|          ) : null}
   463|
   464|          <BlockerList items={ghBlockers} />
   465|          {ghBlockers.length > 0 ? (
   466|            <Pressable style={styles.copyBtn} onPress={() => copyBlockers(ghBlockers, 'GitHub')} testID="ivx-security-box-copy-gh-blockers">
   467|              <Text style={styles.copyBtnText}>Copy blockers</Text>
   468|            </Pressable>
   469|          ) : null}
   470|        </View>
   471|
   472|        {/* Render panel */}
   473|        <SectionHeader
   474|          icon={<Rocket size={20} color={Colors.tint} />}
   475|          title="Render Security Box"
   476|          subtitle="Service · latest deploy · env vars"
   477|        />
   478|        <View style={styles.panel}>
   479|          <StateBanner state={renderState} label="Render" error={renderQ.data?.error ?? renderQ.error?.message} />
   480|          {renderQ.isLoading ? <ActivityIndicator color={Colors.tint} style={styles.loader} /> : null}
   481|
   482|          <View style={styles.block}>
   483|            <Text style={styles.blockTitle}>Service</Text>
   484|            <View style={styles.kvRow}>
   485|              <Text style={styles.kvLabel}>Name</Text>
   486|              <Text style={styles.kvValue}>{renderQ.data?.service?.name ?? '—'}</Text>
   487|            </View>
   488|            <View style={styles.kvRow}>
   489|              <Text style={styles.kvLabel}>Type</Text>
   490|              <Text style={styles.kvValue}>{renderQ.data?.service?.type ?? '—'}</Text>
   491|            </View>
